func solve(n: Int64, x: Int64): Bool {
    // Case N = 0
    if n == 0 {
        // If n=0, it contains 0. If x=0, it starts with 0.
        // If x=0: Contains (T), Starts with x (T) -> Not valid. False.
        // If x!=0: Contains (F) -> Not valid. False.
        return false
    }

    // 1. Check Condition 2: Does it start with x?

    // Find the power of 10 corresponding to the most significant digit (P)
    var p: Int64 = 1
    // Since N <= 10^5, this loop is very fast.
    while (p * 10) <= n {
        p = p * 10
    }

    // Calculate the leading digit (L)
    var leading_digit: Int64 = n / p

    // If the leading digit equals x, it violates the condition.
    if leading_digit == x {
        return false
    }

    // 2. Check Condition 1: Does it contain x?
    var temp_n: Int64 = n
    var has_x: Bool = false

    while temp_n > 0 {
        // Get the last digit
        var digit: Int64 = temp_n % 10

        if digit == x {
            has_x = true
            break
        }

        // Move to the next digit
        temp_n = temp_n / 10
    }

    // Return true only if x was found (Condition 1 met, Condition 2 already passed)
    return has_x
}
